<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('communications.view');$pdo=obtenerConexion();$vista=in_array($_GET['vista']??'',['enviados','fallidos'],true)?$_GET['vista']:'recibidos';$qtxt=trim((string)($_GET['q']??''));$estado=(string)($_GET['estado']??'');$desde=(string)($_GET['desde']??'');$hasta=(string)($_GET['hasta']??'');$pagina=max(1,(int)($_GET['pagina']??1));$lim=25;$pa=[];
if($vista==='recibidos'){$where=' WHERE 1';if(in_array($estado,['recibido','pendiente','respondido','cerrado'],true)){$where.=' AND h.estado=:e';$pa['e']=$estado;}if($qtxt!==''){$where.=' AND (h.asunto LIKE :q OR h.nombre_contacto LIKE :q OR h.correo_contacto LIKE :q)';$pa['q']='%'.$qtxt.'%';}if(preg_match('/^\d{4}-\d{2}-\d{2}$/',$desde)){$where.=' AND h.ultimo_mensaje_at>=:d';$pa['d']=$desde.' 00:00:00';}if(preg_match('/^\d{4}-\d{2}-\d{2}$/',$hasta)){$where.=' AND h.ultimo_mensaje_at<DATE_ADD(:h,INTERVAL 1 DAY)';$pa['h']=$hasta;}$from=' FROM comunicacion_hilos h LEFT JOIN usuarios u ON u.id=h.usuario_id';$qc=$pdo->prepare('SELECT COUNT(*)'.$from.$where);$qc->execute($pa);$total=(int)$qc->fetchColumn();$sql='SELECT h.*,CONCAT_WS(\' \',u.nombre,u.apellido) usuario'.$from.$where.' ORDER BY h.ultimo_mensaje_at DESC LIMIT :lim OFFSET :off';}
else{$where=$vista==='fallidos'?" WHERE c.estado='fallido'":" WHERE c.estado='enviado'";if($qtxt!==''){$where.=' AND (c.asunto LIKE :q OR c.destinatario_enmascarado LIKE :q OR c.tipo LIKE :q)';$pa['q']='%'.$qtxt.'%';}$qc=$pdo->prepare('SELECT COUNT(*) FROM correo_envios c'.$where);$qc->execute($pa);$total=(int)$qc->fetchColumn();$sql='SELECT c.* FROM correo_envios c'.$where.' ORDER BY c.created_at DESC LIMIT :lim OFFSET :off';}
$q=$pdo->prepare($sql);foreach($pa as$k=>$v)$q->bindValue(':'.$k,$v);$q->bindValue(':lim',$lim,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$lim,PDO::PARAM_INT);$q->execute();$filas=$q->fetchAll();cmsCabecera('Correos y comunicaciones','comunicaciones/index.php','Mensajes internos y registro real de correos enviados por Atenea.');?>
<div class="card card-rounded"><div class="card-body"><ul class="nav nav-tabs mb-3"><li class="nav-item"><a class="nav-link <?=$vista==='recibidos'?'active':''?>" href="?vista=recibidos">Recibidos</a></li><li class="nav-item"><a class="nav-link <?=$vista==='enviados'?'active':''?>" href="?vista=enviados">Enviados</a></li><li class="nav-item"><a class="nav-link <?=$vista==='fallidos'?'active':''?>" href="?vista=fallidos">Fallidos</a></li></ul><form class="row g-2 mb-4"><input type="hidden" name="vista" value="<?=atenea_e($vista)?>"><div class="col-md-4"><input class="form-control" name="q" value="<?=atenea_e($qtxt)?>" placeholder="Usuario, correo o asunto"></div><?php if($vista==='recibidos'):?><div class="col-md-2"><select class="form-select" name="estado"><option value="">Todos</option><?php foreach(['recibido','pendiente','respondido','cerrado'] as$e):?><option <?=$estado===$e?'selected':''?>><?=$e?></option><?php endforeach;?></select></div><div class="col-md-2"><input type="date" class="form-control" name="desde" value="<?=atenea_e($desde)?>"></div><div class="col-md-2"><input type="date" class="form-control" name="hasta" value="<?=atenea_e($hasta)?>"></div><?php endif;?><div class="col-md-2"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form><div class="table-responsive"><table class="table table-hover"><thead><tr><?php if($vista==='recibidos'):?><th>Asunto</th><th>Contacto</th><th>Canal</th><th>Estado</th><th>Último mensaje</th><?php else:?><th>Asunto / tipo</th><th>Destinatario</th><th>Estado</th><th>Intentos</th><th>Fecha</th><?php endif;?><th></th></tr></thead><tbody><?php foreach($filas as$f):?><tr><?php if($vista==='recibidos'):?><td><?=atenea_e($f['asunto'])?></td><td><?=atenea_e($f['usuario']?:$f['nombre_contacto'])?><small class="d-block"><?=atenea_e((string)$f['correo_contacto'])?></small></td><td><?=atenea_e($f['canal'])?></td><td><?=atenea_e($f['estado'])?></td><td><?=date('d/m/Y H:i',strtotime($f['ultimo_mensaje_at']))?></td><td><a class="btn btn-sm btn-outline-primary" href="hilo.php?id=<?=$f['id']?>">Ver hilo</a></td><?php else:?><td><?=atenea_e($f['asunto']?:$f['tipo'])?></td><td><?=atenea_e($f['destinatario_enmascarado'])?></td><td><?=atenea_e($f['estado'])?></td><td><?=(int)$f['intento']?></td><td><?=date('d/m/Y H:i',strtotime($f['created_at']))?></td><td><?=atenea_e((string)$f['error_sanitizado'])?></td><?php endif;?></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="6" class="text-center py-5">No hay registros.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();
